+// Use appends a middleware to the tool execution pipeline.
+// Middleware runs after argument validation but before tool execution.
+func (r *ToolRegistry) Use(mw ToolMiddleware) {
+	r.mu.Lock()
+	defer r.mu.Unlock()
+	r.middleware = append(r.middleware, mw)
+}
